      "content": "const { randomUUID } = require('node:crypto');
const projectsStore = require('../projects/store');

function getTasks(projectId, statusFilter) {
  const project = projectsStore.getProjectById(projectId);
  if (!project) return null;
  if (statusFilter) {
    return project.tasks.filter(task => task.status === statusFilter);
  }
  return project.tasks;
}

function createTask(projectId, title) {
  const project = projectsStore.getProjectById(projectId);
  const newTask = { id: randomUUID(), title, status: 'todo' };
  project.tasks.push(newTask);
  return newTask;
}

function updateTaskStatus(projectId, taskId, status) {
  const project = projectsStore.getProjectById(projectId);
  if (!project) return null;
  const task = project.tasks.find(task => task.id === taskId);
  if (task) {
    task.status = status;
  }
  return task;
}

module.exports = { getTasks, createTask, updateTaskStatus };
